// FIX: Execute Command descarta o binário do Webhook.
// Recupera o binário original para o próximo nó poder salvar o arquivo.
const webhookItem = $('Webhook').first();
return [{
  json: webhookItem.json,
  binary: webhookItem.binary
}];

const raw = $json.stdout;

if (!raw) {
  throw new Error('Nenhum stdout recebido do OCR');
}

const data = JSON.parse(raw);

if (data.erro) {
  throw new Error('Erro no OCR: ' + data.erro);
}

return [{ json: { texto: data.texto } }];

let texto = $json.texto || '';

// Junta palavras quebradas no fim da linha com hífen
texto = texto.replace(/-\n/g, '');

// Remove quebras de linha duplicadas
texto = texto.replace(/\n{2,}/g, '\n');

// Remove espaços e tabs duplicados
texto = texto.replace(/[ \t]+/g, ' ');

// Remove linhas com apenas lixo (menos de 3 chars não-alfanuméricos)
texto = texto.replace(/\n[^\wÀ-ÿ]{1,3}\n/g, '\n');

// Trim geral
texto = texto.trim();

return [{ json: { texto_limpo: texto } }];

// Extrai o SQL da resposta da IA
// O nó OpenAI pode retornar o conteúdo em campos diferentes dependendo da versão
const content =
  $json.content ||
  $json.message?.content ||
  $json.choices?.[0]?.message?.content ||
  $json.text ||
  '';

if (!content) {
  throw new Error(
    'Não foi possível extrair o SQL da resposta da IA.\nJSON recebido: ' +
    JSON.stringify($json, null, 2)
  );
}

// Remove blocos de código markdown caso a IA os inclua (```sql ... ```)
let sql = content.trim();
sql = sql.replace(/```sql\s*/gi, '').replace(/```\s*/g, '').trim();

// Validação básica
if (!sql.toUpperCase().startsWith('INSERT')) {
  throw new Error('A IA não retornou um INSERT válido.\nResposta: ' + sql);
}

return [{ json: { sql_insert: sql } }];
